var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"수고했어요. 가져온 기록은 다행히 온전하더군요.","JPN":"お疲れ様でした。いただいた記録は無事でしたよ。","ENG":"Good work. The records you brought back were thankfully intact.","TWN":"辛苦了。帶回來的紀錄幸好是完整的。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이번 의뢰 비용은 계좌로…","JPN":"今回の依頼の報酬は口座に……","ENG":"The payment for this job will be transferred to your account…","TWN":"這次委託的費用會匯到你的帳戶…"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"세 짐승의 범이라는 건 뭐지?","JPN":"3匹のケモノの虎とはなんだ？","ENG":"What's the Tiger of the Three Beasts?","TWN":"三隻野獸的虎是什麼？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…직설적이네요. 저는 충분히 주의를 드렸을 텐데요.","JPN":"……ストレートですね。注意したはずです。","ENG":"…Straight to the point. I'm pretty sure I warned you.","TWN":"…真直接。我應該已經警告過你了。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리국의 기밀은 함부로 엿보면 돌이킬 수 없게 되는 거라고.","JPN":"管理局の機密を勝手に覗くと、取り返しがつかなくなると。","ENG":"It's best not to pry into the Administration's classified material.","TWN":"管理局的機密，隨便偷看可是會造成無法挽回的後果的。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"연기할 필요 없어.","JPN":"演技する必要はない。","ENG":"Cut the act.","TWN":"不用裝了。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"내가 말했지? 내 눈엔 그 사람의 과거가 보인다고.","JPN":"言っただろう？　私の目にはその人の過去が見える。","ENG":"I told you, didn't I? I can see a man's past with these eyes.","TWN":"我不是說過嗎？我的眼睛能看到那個人的過去。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신이 누구고 뭘 원하는지도, 그걸 위해 필요한 사람을 찾고 있었단 것도 알아.","JPN":"お前が誰で何を求めているかも、そのために必要な人間を探していることも知っている。","ENG":"I know who you are, what you want, and that you've been looking for someone to help you get it.","TWN":"我知道你是誰，想要什麼，也知道你一直在尋找你需要的人。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신은 처음부터 내가 당신과 협력할 계기를 만들기 위해 일부러 이 의뢰를 준비했지. 틀렸나?","JPN":"お前は、私がお前に協力するきっかけを作るために、わざとこの依頼を用意した。違うか？","ENG":"This job, this whole setup, was your way of making me cooperate. Wasn't it?","TWN":"你從一開始就為了製造我與你合作的契機，特地準備了這個委託。我說錯了嗎？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이거, 완전히 간파당했군요.","JPN":"これは、完全に見抜かれましたね。","ENG":"Looks like you've completely figured it out.","TWN":"這下，完全被看穿了。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"간파하지 못했다면 애초에 당신을 영입할 이유도 없었겠지만요.","JPN":"見抜けなかったら、そもそもあなたをスカウトする理由もなくなっていたでしょうけど。","ENG":"Then again, if you couldn't, I wouldn't have tried to recruit you in the first place.","TWN":"如果無法看穿，我一開始就不會找你加入。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"지난 번에 했던 제안은 아직 유효하겠지?","JPN":"前回の提案はまだ有効か？","ENG":"That offer you made last time. It still stands, right?","TWN":"上次的提議還有效吧？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신의 협력자가 되면, 이터니움 속 남자에 대해 더 많은 정보를 얻게 된다는 거 말이야.","JPN":"お前に協力すれば、エタニウムの中の男についてもっと情報を手に入れられるというやつだ。","ENG":"That if I join you, I'll learn more about the man inside the Eternium.","TWN":"如果成為你的合作者，就能得到更多關於永恆之金中那個男人的情報。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"좋은 눈빛이네요. 당신의 그 입도 무거울 거라고 믿어보죠.","JPN":"いい目ですね。あなたの口が堅いと信じてみましょう。","ENG":"I like that look in your eyes. And I'll trust that your lips are just as sealed.","TWN":"眼神很好。我相信你的嘴巴也很緊。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"세 짐승은 심연이라 불리는 이 세상 밖으로부터 온 생물.","JPN":"3匹のケモノは、深淵と呼ばれるこの世界の外側から来た生き物。","ENG":"The Three Beasts are creatures from beyond this world, from a place called the Abyss.","TWN":"三隻野獸是來自被稱為深淵的這個世界之外的生物。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리국은 과거, 몇 번이나 짐승들을 토벌하려 했지만 번번이 실패했어요.","JPN":"管理局は過去、何度もケモノの討伐を試みたものの、毎回失敗しています。","ENG":"The Administration tried multiple times to hunt them down… and failed every time.","TWN":"管理局過去曾多次試圖討伐野獸，但每次都失敗了。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"짐승을 죽여도 그것들은 자신을 사냥한 자들에게 저주를 내리고, 그 저주를 양분 삼아 다시 태어나거든요.","JPN":"ケモノを殺したところで、やつらは自分を殺した者に呪いをかけ、その呪いを糧にして再び生まれるのです。","ENG":"Even when killed, the Beasts curse their slayers and use that curse to be reborn.","TWN":"因為野獸即使被殺，也會對狩獵自己的人施加詛咒，並以詛咒為養分再次重生。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리국은 죽지 않는 범을 가둬 놓으려고 여러 방편을 세웠지만, 영겁을 사는 범이 현실을 침범하는 건 시간 문제였습니다.","JPN":"管理局は不死の虎を閉じ込めようと様々な対策を講じましたが、永劫を生きる虎が現実を襲うのは時間の問題でした。","ENG":"The Administration came up with all sorts of ways to contain the immortal Tiger. But it was only a matter of time before it started invading the Normalside.","TWN":"管理局設置了多種方法來囚禁不死的老虎，但這隻活了永劫的老虎，侵犯現實只是時間問題。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그런데, 짐승 중 하나인 범이 어느 날을 기점으로 자취를 감췄어요. 어떤 기록도 남기지 않은 채 말이죠.","JPN":"しかし、虎はある日を境に姿を消しました。何の記録も残さずね。","ENG":"And then one day, the Tiger just vanished. Left no trace. Not even in the records.","TWN":"然而，其中一隻野虎在某一天突然消失了。沒有留下任何紀錄。"},"stage":{"bg":"VOID","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…정보 오염이로군.","JPN":"……情報汚染だな。","ENG":"…So it's data corruption.","TWN":"…是資訊污染。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저도 그렇게 생각해요. 지금 당신이 겪고 있는 상황과도 맞물리는 점이 있죠.","JPN":"僕もそう思います。あなたの状況と辻褄が合う部分もありますね。","ENG":"That's my guess too. It lines up with what you're going through.","TWN":"我也這麼認為。這也與你現在經歷的情況不謀而合。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 그 정보 오염으로 소실된 기억을 복원할 수만 있다면, 거기에 이지수 씨 <color=#ffd34c>가족</color>의 행방이 있을 지도 모릅니다.","JPN":"もしかすると、その情報汚染のせいで失った記憶を復元することさえできれば、ムラサメさんの<color=#ffd34c>家族</color>の行方も分かるかもしれません。","ENG":"And if we can restore the memories lost due to that data corruption, we might be able to uncover the whereabouts of your <color=#ffd34c>family</color>.","TWN":"如果能恢復因資訊污染而消失的記憶，或許就能找到你<color=#ffd34c>家人</color>的下落。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"이것에 대해선 얼마나 알고 있지?","JPN":"これについてはどこまで知っている？","ENG":"How much do you know about it?","TWN":"你對這個了解多少？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"검은색의 이터니움이군요.","JPN":"黒いエタニウムですか。","ENG":"You mean the Dark Eternium?","TWN":"是黑色的永恆之金。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 광물 덩어리가 나한테 어떤 기억을 보여줬어.","JPN":"その鉱物の塊が、私にある記憶を見せてくれた。","ENG":"That lump of mineral… showed me a memory.","TWN":"那塊礦物，讓我看到了一些記憶。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};